mapper.select:
/* com.erns.coching.member.mapper.MemberDeviceInfoDAO.load */

SELECT

FROM T_MEMB_DEVICE_INF AA

	AND AA.APP_ID 	= #{appId	, jdbcType=VARCHAR}

mapper.insert:
/* com.erns.coching.member.mapper.MemberDeviceInfoDAO.insert */

INSERT INTO T_MEMB_DEVICE_INF(
	APP_ID, MEMB_SEQ, DEV_TYPE, CHNG_DTTM
)
VALUES (
	  #{appId		, jdbcType=VARCHAR}
	, #{membSeq		, jdbcType=INTEGER}
	, #{deviceType	, jdbcType=VARCHAR}
	, now()
)

/* com.erns.coching.member.mapper.MemberDeviceInfoDAO.update */

UPDATE T_USER_DEVICE
	   USER_SEQ 	= #{membSeq	, jdbcType=INTEGER}
	 , CHNG_DTTM	= now()

	AND APP_ID 	= #{value	, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.member.mapper.MemberDeviceInfoDAO.delete */

DELETE FROM T_MEMB_DEVICE_INF

	AND APP_ID 	= #{value	, jdbcType=VARCHAR}

/* com.erns.coching.member.mapper.MemberDeviceInfoDAO.deleteWhere */

DELETE FROM T_MEMB_DEVICE_INF AA

	AND AA.MEMB_SEQ = #{userSeq , jdbcType=INTEGER}
